// 导出一个验证环境变量的函数
export function validateEnv(): Env {
  // 使用envSchema对process.env进行安全解析
  const result = envSchema.safeParse(process.env)

  // 检查解析是否成功
  if (!result.success) {
    // 如果解析失败，格式化错误信息
    const formatted = result.error.issues
      // 遍历每个错误问题，格式化为"path: message"的形式
      .map((issue) => `  - ${issue.path.join('.')}: ${issue.message}`)
      // 将所有格式化后的错误信息连接成一个字符串，用换行符分隔
      .join('\n')
    // 抛出一个包含详细错误信息的错误对象
    throw new Error(`环境变量校验失败:\n${formatted}`)
  }

  // 如果解析成功，返回解析后的数据
  return result.data
}
